     5→//! Muster command - List all Heats with summary information
     6→//!
     7→//! Implements the muster query operation which displays all heats
     8→//! with their status and pace completion counts.
     9→
    10→use std::path::PathBuf;
    11→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_HeatStatus as HeatStatus, jjrg_PaceState as PaceState};
    12→use crate::jjrp_print::{jjrp_Table, jjrp_Column, jjrp_Align};
    13→
    14→/// Arguments for muster command
    15→#[derive(clap::Args, Debug)]
    16→pub struct jjrmu_MusterArgs {
    17→    /// Path to the Gallops JSON file
    18→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
    19→    pub file: PathBuf,
    20→
    21→    /// Filter by heat status (racing, stabled)
    22→    #[arg(long)]
    23→    pub status: Option<String>,
    24→}
    25→
    26→/// Run the muster command - list Heats as TSV
    27→pub fn jjrmu_run_muster(args: jjrmu_MusterArgs) -> i32 {
    28→    let gallops = match Gallops::jjrg_load(&args.file) {
    29→        Ok(g) => g,
    30→        Err(e) => {
    31→            eprintln!("jjx_muster: error: {}", e);
    32→            return 1;
    33→        }
    34→    };
    35→
    36→    // Collect heats with status info for sorting
    37→    let mut heats_by_status: Vec<(&String, &crate::jjrg_gallops::jjrg_Heat)> = gallops.heats.iter().collect();
    38→
    39→    // Apply status filter if specified
    40→    if let Some(ref filter_status) = args.status {
    41→        let filter_lowercase = filter_status.to_lowercase();
    42→        heats_by_status.retain(|(_, heat)| {
    43→            let heat_status_str = match heat.status {
    44→                HeatStatus::Racing => "racing",
    45→                HeatStatus::Stabled => "stabled",
    46→                HeatStatus::Retired => "retired",
    47→            };
    48→            heat_status_str == filter_lowercase
    49→        });
    50→    }
    51→
    52→    // Sort: racing first, then stabled, then retired
    53→    heats_by_status.sort_by(|a, b| {
    54→        let a_status_order = match a.1.status {
    55→            HeatStatus::Racing => 0,
    56→            HeatStatus::Stabled => 1,
    57→            HeatStatus::Retired => 2,
    58→        };
    59→        let b_status_order = match b.1.status {
    60→            HeatStatus::Racing => 0,
    61→            HeatStatus::Stabled => 1,
    62→            HeatStatus::Retired => 2,
    63→        };
    64→        a_status_order.cmp(&b_status_order)
    65→    });
    66→
    67→    // Set up table with column definitions
    68→    let mut table = jjrp_Table::jjrp_new(vec![
    69→        jjrp_Column::new("₣Fire", jjrp_Align::Left),
    70→        jjrp_Column::new("Silks", jjrp_Align::Left),
    71→        jjrp_Column::new("Status", jjrp_Align::Left),
    72→        jjrp_Column::new("Done", jjrp_Align::Right),
    73→        jjrp_Column::new("Total", jjrp_Align::Right),
    74→    ]);
    75→
    76→    // Measure all rows to compute column widths
    77→    for (key, heat) in &heats_by_status {
    78→        // Count paces where state != Abandoned
    79→        let defined_count = heat.paces.values().filter(|pace| {
    80→            if let Some(tack) = pace.tacks.first() {
    81→                tack.state != PaceState::Abandoned
    82→            } else {
    83→                true
    84→            }
    85→        }).count();
    86→
    87→        // Count paces where state == Complete
    88→        let completed_count = heat.paces.values().filter(|pace| {
    89→            if let Some(tack) = pace.tacks.first() {
    90→                tack.state == PaceState::Complete
    91→            } else {
    92→                false
    93→            }
    94→        }).count();
    95→
    96→        let status_str = match heat.status {
    97→            HeatStatus::Racing => "racing",
    98→            HeatStatus::Stabled => "stabled",
    99→            HeatStatus::Retired => "retired",
   100→        };
   101→
   102→        table.jjrp_measure(&[
   103→            key,
   104→            &heat.silks,
   105→            status_str,
   106→            &completed_count.to_string(),
   107→            &defined_count.to_string(),
   108→        ]);
   109→    }
   110→
   111→    // Print header and separator
   112→    table.jjrp_print_header();
   113→    table.jjrp_print_separator();
   114→
   115→    // Print data rows
   116→    for (key, heat) in heats_by_status {
   117→        // Count paces where state != Abandoned
   118→        let defined_count = heat.paces.values().filter(|pace| {
   119→            if let Some(tack) = pace.tacks.first() {
   120→                tack.state != PaceState::Abandoned
   121→            } else {
   122→                true
   123→            }
   124→        }).count();
   125→
   126→        // Count paces where state == Complete
   127→        let completed_count = heat.paces.values().filter(|pace| {
   128→            if let Some(tack) = pace.tacks.first() {
   129→                tack.state == PaceState::Complete
   130→            } else {
   131→                false
   132→            }
   133→        }).count();
   134→
   135→        let status_str = match heat.status {
   136→            HeatStatus::Racing => "racing",
   137→            HeatStatus::Stabled => "stabled",
   138→            HeatStatus::Retired => "retired",
   139→        };
   140→
   141→        table.jjrp_print_row(&[
   142→            key,
   143→            &heat.silks,
   144→            status_str,
   145→            &completed_count.to_string(),
   146→            &defined_count.to_string(),
   147→        ]);
   148→    }
   149→
   150→    0
   151→}
