     5→//! Saddle command - Return context needed to saddle up on a Heat
     6→
     7→use std::fs;
     8→use std::path::PathBuf;
     9→
    10→use crate::jjrf_favor::jjrf_Firemark as Firemark;
    11→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_HeatStatus as HeatStatus, jjrg_PaceState as PaceState};
    12→use crate::jjrp_print::{jjrp_Table, jjrp_Column, jjrp_Align};
    13→use crate::jjrs_steeplechase::{jjrs_get_entries, jjrs_ReinArgs};
    14→use crate::jjrq_query::jjrq_resolve_default_heat;
    15→use crate::jjrc_core::jjrc_timestamp_full;
    16→use crate::jjrn_notch::jjrn_format_session_message;
    17→
    18→/// Arguments for saddle command
    19→#[derive(clap::Args, Debug)]
    20→pub struct jjrsd_SaddleArgs {
    21→    /// Path to the Gallops JSON file
    22→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
    23→    pub file: PathBuf,
    24→
    25→    /// Target Heat identity (Firemark). If omitted, uses first racing heat.
    26→    pub firemark: Option<String>,
    27→}
    28→
    29→/// Run the saddle command - return Heat context
    30→pub async fn jjrsd_run_saddle(args: jjrsd_SaddleArgs) -> i32 {
    31→    let gallops = match Gallops::jjrg_load(&args.file) {
    32→        Ok(g) => g,
    33→        Err(e) => {
    34→            eprintln!("jjx_saddle: error: {}", e);
    35→            return 1;
    36→        }
    37→    };
    38→
    39→    // Resolve firemark: use provided value or auto-select first racing heat
    40→    let firemark_str = match args.firemark {
    41→        Some(fm) => fm,
    42→        None => {
    43→            match jjrq_resolve_default_heat(&gallops) {
    44→                Ok(fm) => fm,
    45→                Err(e) => {
    46→                    eprintln!("jjx_saddle: error: {}", e);
    47→                    return 1;
    48→                }
    49→            }
    50→        }
    51→    };
    52→
    53→    let firemark = match Firemark::jjrf_parse(&firemark_str) {
    54→        Ok(fm) => fm,
    55→        Err(e) => {
    56→            eprintln!("jjx_saddle: error: {}", e);
    57→            return 1;
    58→        }
    59→    };
    60→
    61→    let heat_key = firemark.jjrf_display();
    62→    let heat = match gallops.heats.get(&heat_key) {
    63→        Some(h) => h,
    64→        None => {
    65→            eprintln!("jjx_saddle: error: Heat '{}' not found", heat_key);
    66→            return 1;
    67→        }
    68→    };
    69→
    70→    // Check if heat is stabled (cannot saddle stabled heat)
    71→    if heat.status == HeatStatus::Stabled {
    72→        eprintln!("jjx_saddle: error: Cannot saddle stabled heat '{}'", heat_key);
    73→        return 1;
    74→    }
    75→
    76→    // Read paddock file content
    77→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
    78→        Ok(content) => content,
    79→        Err(e) => {
    80→            eprintln!("jjx_saddle: error reading paddock file '{}': {}", heat.paddock_file, e);
    81→            return 1;
    82→        }
    83→    };
    84→
    85→    // Get recent steeplechase entries
    86→    let recent_work = jjrs_get_entries(&jjrs_ReinArgs {
    87→        firemark: firemark.jjrf_as_str().to_string(),
    88→        limit: 10,
    89→    }).unwrap_or_default();
    90→
    91→    // Find first actionable pace (rough or bridled)
    92→    let mut pace_coronet: Option<String> = None;
    93→    let mut pace_silks: Option<String> = None;
    94→    let mut pace_state: Option<String> = None;
    95→    let mut spec: Option<String> = None;
    96→    let mut direction: Option<String> = None;
    97→
    98→    for coronet_key in &heat.order {
    99→        if let Some(pace) = heat.paces.get(coronet_key) {
   100→            if let Some(tack) = pace.tacks.first() {
   101→                match tack.state {
   102→                    PaceState::Rough | PaceState::Bridled => {
   103→                        pace_coronet = Some(coronet_key.clone());
   104→                        pace_silks = Some(tack.silks.clone());
   105→                        pace_state = Some(match tack.state {
   106→                            PaceState::Rough => "rough".to_string(),
   107→                            PaceState::Bridled => "bridled".to_string(),
   108→                            _ => unreachable!(),
   109→                        });
   110→                        spec = Some(tack.text.clone());
   111→                        if tack.state == PaceState::Bridled {
   112→                            direction = tack.direction.clone();
   113→                        }
   114→                        break;
   115→                    }
   116→                    _ => continue,
   117→                }
   118→            }
   119→        }
   120→    }
   121→
   122→    // Determine heat status string
   123→    let status_str = match heat.status {
   124→        HeatStatus::Racing => "racing",
   125→        HeatStatus::Stabled => "stabled",
   126→        HeatStatus::Retired => "retired",
   127→    };
   128→
   129→    // Output plain text format
   130→    println!("Heat: {} ({}) [{}]", heat.silks, heat_key, status_str);
   131→    println!("Paddock: {}", heat.paddock_file);
   132→    println!();
   133→    println!("Paddock-content:");
   134→    for line in paddock_content.lines() {
   135→        println!("  {}", line);
   136→    }
   137→    println!();
   138→
   139→    if let Some(coronet) = pace_coronet {
   140→        if let Some(silks) = pace_silks {
   141→            if let Some(state) = pace_state {
   142→                println!("Next: {} ({}) [{}]", silks, coronet, state);
   143→                println!();
   144→                if let Some(spec_text) = spec {
   145→                    println!("Spec:");
   146→                    for line in spec_text.lines() {
   147→                        println!("  {}", line);
   148→                    }
   149→                    println!();
   150→                }
   151→                if let Some(dir_text) = direction {
   152→                    println!("Direction:");
   153→                    for line in dir_text.lines() {
   154→                        println!("  {}", line);
   155→                    }
   156→                    println!();
   157→                }
   158→            }
   159→        }
   160→    }
   161→
   162→    // Output recent work table
   163→    // Filter entries to only show action codes 'n' (notch), 'A' (approach), 'd' (discussion)
   164→    let filtered_work: Vec<_> = recent_work.iter().filter(|entry| {
   165→        if let Some(ref action) = entry.action {
   166→            action == "n" || action == "A" || action == "d"
   167→        } else {
   168→            false
   169→        }
   170→    }).collect();
   171→
   172→    if !filtered_work.is_empty() {
   173→        println!("Recent-work:");
   174→
   175→        let mut table = jjrp_Table::jjrp_new(vec![
   176→            jjrp_Column::new("Commit", jjrp_Align::Left),
   177→            jjrp_Column::new("Identity", jjrp_Align::Left),
   178→            jjrp_Column::new("Subject", jjrp_Align::Left),
   179→        ]);
   180→
   181→        // Measure all rows to compute column widths
   182→        for entry in &filtered_work {
   183→            let identity_str = if let Some(ref coronet) = entry.coronet {
   184→                coronet.clone()
   185→            } else {
   186→                heat_key.clone()
   187→            };
   188→            table.jjrp_measure(&[
   189→                &entry.commit,
   190→                &identity_str,
   191→                &entry.subject,
   192→            ]);
   193→        }
   194→
   195→        // Print header and separator
   196→        table.jjrp_print_header();
   197→        table.jjrp_print_separator();
   198→
   199→        // Print data rows
   200→        for entry in &filtered_work {
   201→            let identity_str = if let Some(ref coronet) = entry.coronet {
   202→                coronet.clone()
   203→            } else {
   204→                heat_key.clone()
   205→            };
   206→            table.jjrp_print_row(&[
   207→                &entry.commit,
   208→                &identity_str,
   209→                &entry.subject,
   210→            ]);
   211→        }
   212→    }
   213→
   214→    // Check if session probe is needed (gap > 1 hour or no commits)
   215→    let last_timestamp = recent_work.first().map(|e| e.timestamp.as_str());
   216→    if crate::jjrc_core::jjrc_needs_session_probe(last_timestamp) {
   217→        println!();
   218→        match vvc::vvcp_probe().await {
   219→            Ok(probe_result) => {
   220→                // Get timestamp for session marker
   221→                let timestamp = jjrc_timestamp_full();
   222→
   223→                // Build commit message: subject + body
   224→                let subject = jjrn_format_session_message(&firemark, &timestamp);
   225→                let message = format!("{}\n\n{}", subject, probe_result);
   226→
   227→                // Create session chalk commit (allow_empty: true, no_stage: true)
   228→                let commit_args = vvc::vvcc_CommitArgs {
   229→                    prefix: None,
   230→                    message: Some(message),
   231→                    allow_empty: true,
   232→                    no_stage: true,
   233→                    size_limit: vvc::VVCG_SIZE_LIMIT,
   234→                    warn_limit: vvc::VVCG_WARN_LIMIT,
   235→                };
   236→
   237→                match vvc::commit(&commit_args) {
   238→                    0 => {
   239→                        // Get the commit hash of HEAD
   240→                        if let Ok(output) = std::process::Command::new("git")
   241→                            .args(["rev-parse", "--short", "HEAD"])
   242→                            .output()
   243→                        {
   244→                            if output.status.success() {
   245→                                let commit_hash = String::from_utf8_lossy(&output.stdout).trim().to_string();
   246→                                println!("Session-marker: {} ({})", commit_hash, timestamp);
   247→                            } else {
   248→                                println!("Session-marker: created ({})", timestamp);
   249→                            }
   250→                        } else {
   251→                            println!("Session-marker: created ({})", timestamp);
   252→                        }
   253→                    }
   254→                    _ => {
   255→                        eprintln!("jjx_saddle: warning: failed to create session marker commit");
   256→                    }
   257→                }
   258→            }
   259→            Err(e) => {
   260→                eprintln!("jjx_saddle: warning: probe failed: {}", e);
   261→            }
   262→        }
   263→    }
   264→
   265→    0
   266→}
