     5→//! Column table formatting for JJK output
     6→//!
     7→//! Provides structured column layout to eliminate magic numbers/strings
     8→//! from formatted output operations. Single source of truth for headers,
     9→//! widths, and alignment.
    10→
    11→/// Gap between columns
    12→pub const JJRP_COLUMN_GAP: usize = 2;
    13→
    14→/// Minimum column width
    15→pub const JJRP_MIN_WIDTH: usize = 5;
    16→
    17→/// Column alignment
    18→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
    19→pub enum jjrp_Align {
    20→    Left,
    21→    Right,
    22→}
    23→
    24→/// Column definition
    25→#[derive(Debug, Clone)]
    26→pub struct jjrp_Column {
    27→    /// Header text (single source of truth)
    28→    pub header: &'static str,
    29→    /// Minimum width (defaults to header.len())
    30→    pub min_width: usize,
    31→    /// Alignment
    32→    pub align: jjrp_Align,
    33→}
    34→
    35→impl jjrp_Column {
    36→    /// Create a new column with default min_width from header
    37→    pub fn new(header: &'static str, align: jjrp_Align) -> Self {
    38→        Self {
    39→            header,
    40→            min_width: header.len().max(JJRP_MIN_WIDTH),
    41→            align,
    42→        }
    43→    }
    44→
    45→    /// Create a new column with explicit min_width
    46→    pub fn with_width(header: &'static str, min_width: usize, align: jjrp_Align) -> Self {
    47→        Self {
    48→            header,
    49→            min_width: min_width.max(JJRP_MIN_WIDTH),
    50→            align,
    51→        }
    52→    }
    53→}
    54→
    55→/// Table with columns and computed widths
    56→pub struct jjrp_Table {
    57→    columns: Vec<jjrp_Column>,
    58→    widths: Vec<usize>,
    59→}
    60→
    61→impl jjrp_Table {
    62→    /// Create a new table with the given columns
    63→    pub fn jjrp_new(columns: Vec<jjrp_Column>) -> Self {
    64→        let widths = columns.iter().map(|c| c.min_width).collect();
    65→        Self { columns, widths }
    66→    }
    67→
    68→    /// Update column widths based on a data row
    69→    pub fn jjrp_measure(&mut self, row: &[&str]) {
    70→        for (i, value) in row.iter().enumerate() {
    71→            if i < self.widths.len() {
    72→                self.widths[i] = self.widths[i].max(value.len());
    73→            }
    74→        }
    75→    }
    76→
    77→    /// Print the header row
    78→    pub fn jjrp_print_header(&self) {
    79→        let mut parts = Vec::new();
    80→        for (i, col) in self.columns.iter().enumerate() {
    81→            let width = self.widths[i];
    82→            let formatted = match col.align {
    83→                jjrp_Align::Left => format!("{:<width$}", col.header, width = width),
    84→                jjrp_Align::Right => format!("{:>width$}", col.header, width = width),
    85→            };
    86→            parts.push(formatted);
    87→        }
    88→        println!("{}", parts.join(&" ".repeat(JJRP_COLUMN_GAP)));
    89→    }
    90→
    91→    /// Print a separator line using computed widths
    92→    /// Uses box drawing character to avoid markdown interpretation of dashes
    93→    pub fn jjrp_print_separator(&self) {
    94→        let mut parts = Vec::new();
    95→        for width in &self.widths {
    96→            parts.push("─".repeat(*width));
    97→        }
    98→        println!("{}", parts.join(&" ".repeat(JJRP_COLUMN_GAP)));
    99→    }
   100→
   101→    /// Print a data row
   102→    pub fn jjrp_print_row(&self, values: &[&str]) {
   103→        let mut parts = Vec::new();
   104→        for (i, value) in values.iter().enumerate() {
   105→            if i < self.columns.len() {
   106→                let width = self.widths[i];
   107→                let col = &self.columns[i];
   108→                let formatted = match col.align {
   109→                    jjrp_Align::Left => format!("{:<width$}", value, width = width),
   110→                    jjrp_Align::Right => format!("{:>width$}", value, width = width),
   111→                };
   112→                parts.push(formatted);
   113→            }
   114→        }
   115→        println!("{}", parts.join(&" ".repeat(JJRP_COLUMN_GAP)));
   116→    }
   117→}
   118→
   119→#[cfg(test)]
   120→mod tests {
   121→    use super::*;
   122→
   123→    #[test]
   124→    fn test_column_new() {
   125→        let col = jjrp_Column::new("Test", jjrp_Align::Left);
   126→        assert_eq!(col.header, "Test");
   127→        assert_eq!(col.min_width, JJRP_MIN_WIDTH);
   128→        assert_eq!(col.align, jjrp_Align::Left);
   129→    }
   130→
   131→    #[test]
   132→    fn test_column_with_width() {
   133→        let col = jjrp_Column::with_width("ID", 10, jjrp_Align::Right);
   134→        assert_eq!(col.header, "ID");
   135→        assert_eq!(col.min_width, 10);
   136→        assert_eq!(col.align, jjrp_Align::Right);
   137→    }
   138→
   139→    #[test]
   140→    fn test_table_measure() {
   141→        let columns = vec![
   142→            jjrp_Column::new("Name", jjrp_Align::Left),
   143→            jjrp_Column::new("ID", jjrp_Align::Right),
   144→        ];
   145→        let mut table = jjrp_Table::jjrp_new(columns);
   146→
   147→        // Initial widths are min_width
   148→        assert_eq!(table.widths[0], JJRP_MIN_WIDTH);
   149→        assert_eq!(table.widths[1], JJRP_MIN_WIDTH);
   150→
   151→        // Measure a row with longer values
   152→        table.jjrp_measure(&["Very Long Name", "12345"]);
   153→        assert_eq!(table.widths[0], 14); // "Very Long Name".len()
   154→        assert_eq!(table.widths[1], JJRP_MIN_WIDTH); // Still min because "12345" is shorter
   155→    }
   156→
   157→    #[test]
   158→    fn test_table_output() {
   159→        let columns = vec![
   160→            jjrp_Column::new("₣Fire", jjrp_Align::Left),
   161→            jjrp_Column::new("Silks", jjrp_Align::Left),
