   169→/// Get steeplechase entries for a heat (library function)
   170→pub fn jjrs_get_entries(args: &jjrs_ReinArgs) -> Result<Vec<jjrs_SteeplechaseEntry>, String> {
   171→    let firemark = Firemark::jjrf_parse(&args.firemark)
   172→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   173→
   174→    let firemark_raw = firemark.jjrf_as_str();
   175→
   176→    // Build the grep pattern for git log
   177→    // Format: jjb:HALLMARK:IDENTITY:ACTION: message
   178→    // Pattern matches both heat-level (₣XX) and pace-level (₢XX...) entries
   179→    let grep_pattern = format!(
   180→        "^jjb:[^:]+:({}{}|{}{})",
   181→        FIREMARK_PREFIX, firemark_raw,
   182→        CORONET_PREFIX, firemark_raw
   183→    );
   184→
   185→    let output = Command::new("git")
   186→        .args([
   187→            "log",
   188→            "--all",
   189→            "--extended-regexp",
   190→            &format!("--grep={}", grep_pattern),
   191→            "--format=%ai\t%h\t%s",
   192→        ])
   193→        .output()
   194→        .map_err(|e| format!("Failed to run git log: {}", e))?;
   195→
   196→    if !output.status.success() {
   197→        let stderr = String::from_utf8_lossy(&output.stderr);
   198→        return Err(format!("git log failed: {}", stderr));
   199→    }
   200→
   201→    let stdout = String::from_utf8_lossy(&output.stdout);
   202→
   203→    let entries: Vec<jjrs_SteeplechaseEntry> = stdout
   204→        .lines()
   205→        .filter_map(|line| zjjrs_parse_log_line(line, firemark_raw))
   206→        .take(args.limit)
   207→        .collect();
   208→
   209→    Ok(entries)
   210→}
   211→
   212→/// Run jjx_rein command (CLI wrapper)
   213→/// Outputs column-aligned plain text table with header and separator
   214→pub fn jjrs_run(args: jjrs_ReinArgs) -> i32 {
   215→    match jjrs_get_entries(&args) {
   216→        Ok(entries) => {
   217→            // Set up table with column definitions
   218→            let mut table = jjrp_Table::jjrp_new(vec![
   219→                jjrp_Column::new("Timestamp", jjrp_Align::Left),
   220→                jjrp_Column::new("Commit", jjrp_Align::Left),
   221→                jjrp_Column::new("Act", jjrp_Align::Left),
   222→                jjrp_Column::new("Affil", jjrp_Align::Left),
   223→                jjrp_Column::new("Subject", jjrp_Align::Left),
   224→            ]);
   225→
   226→            // Measure all rows to compute column widths
   227→            for entry in &entries {
   228→                let action_str = entry.action.as_ref().map(|a| format!("[{}]", a)).unwrap_or_else(|| String::new());
   229→                let affil_str = if let Some(ref coronet) = entry.coronet {
   230→                    coronet.clone()
   231→                } else {
   232→                    // Extract firemark from the first 2 chars after coronet prefix in firemark
   233→                    // Since we called with a firemark, we need to reconstruct it
   234→                    // Parse the target firemark from args - it's passed as a raw string
   235→                    format!("₣{}", args.firemark)
   236→                };
   237→                table.jjrp_measure(&[
   238→                    &entry.timestamp,
   239→                    &entry.commit,
   240→                    &action_str,
   241→                    &affil_str,
   242→                    &entry.subject,
   243→                ]);
   244→            }
   245→
   246→            // Print header and separator
   247→            table.jjrp_print_header();
   248→            table.jjrp_print_separator();
   249→
   250→            // Print data rows
   251→            for entry in &entries {
   252→                let action_str = entry.action.as_ref().map(|a| format!("[{}]", a)).unwrap_or_else(|| String::new());
   253→                let affil_str = if let Some(ref coronet) = entry.coronet {
   254→                    coronet.clone()
   255→                } else {
   256→                    format!("₣{}", args.firemark)
   257→                };
   258→                table.jjrp_print_row(&[
   259→                    &entry.timestamp,
   260→                    &entry.commit,
   261→                    &action_str,
   262→                    &affil_str,
   263→                    &entry.subject,
   264→                ]);
   265→            }
   266→
   267→            0
   268→        }
   269→        Err(e) => {
   270→            eprintln!("jjx_rein: error: {}", e);
   271→            1
   272→        }
   273→    }
   274→}
